import { defineComponentSlotStyle } from "@yamada-ui/react"

export const flipStyle = defineComponentSlotStyle({
  base: {
    from: {},
    item: {
      backfaceVisibility: "hidden",
      position: "absolute",
      top: 0,
    },
    root: {
      position: "relative",
      rounded: "l1",
      userSelect: "none",
      _readOnly: {
        layerStyle: "readOnly",
      },
      _disabled: {
        layerStyle: "disabled",
      },
    },
    to: {},
  },
})

export type FlipStyle = typeof flipStyle

import type { KeyframeIdent } from "@yamada-ui/react"
import { useState } from "react"
import { a11y, page, render } from "#test/browser"
import { noop } from "@yamada-ui/react"
import { BoxIcon } from "../icon"
import { Flip } from "./"

describe("<Flip />", () => {
  test("renders component correctly", async () => {
    await a11y(<Flip from="ON" to="OFF" />)
  })

  test("applies custom `aria-label`", async () => {
    await render(<Flip aria-label="Toggle icon" from="ON" to="OFF" />)

    await expect
      .element(page.getByRole("button"))
      .toHaveAttribute("aria-label", "Toggle icon")
  })

  test("sets `displayName` correctly", () => {
    expect(Flip.displayName).toBe("FlipRoot")
  })

  test("sets `className` correctly", async () => {
    await render(<Flip from="ON" to="OFF" />)
    await expect
      .element(page.getByText("ON").element().parentElement)
      .toHaveClass("ui-flip__root")
    await expect
      .element(page.getByText("ON"))
      .toHaveClass("ui-flip__item", "ui-flip__item--from")
    await expect
      .element(page.getByText("OFF"))
      .toHaveClass("ui-flip__item", "ui-flip__item--to")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Flip from="ON" to="OFF" />)
    expect(page.getByText("ON").element().parentElement?.tagName).toBe("BUTTON")
  })

  test("should render Flip with value and onChange", async () => {
    const TestComponent = () => {
      const [value, onChange] = useState<KeyframeIdent>("to")

      return (
        <Flip
          from={<BoxIcon />}
          to={<BoxIcon />}
          value={value}
          onChange={onChange}
        />
      )
    }

    const { user } = await render(<TestComponent />)

    const button = page.getByRole("button").element() as HTMLButtonElement
    expect(button).toHaveAttribute("data-value", "to")

    await user.click(button)

    await vi.waitFor(() => {
      expect(button).toHaveAttribute("data-value", "from")
    })
  })

  test("should be read only", async () => {
    const { user } = await render(
      <Flip from={<BoxIcon />} readOnly to={<BoxIcon />} />,
    )

    const button = page.getByRole("button").element() as HTMLButtonElement
    expect(button).toHaveAttribute("data-value", "from")

    await user.click(button)
    expect(button).toHaveAttribute("data-value", "from")
  })

  test("should be disabled", async () => {
    await render(<Flip disabled from={<BoxIcon />} to={<BoxIcon />} />)

    const button = page.getByRole("button").element() as HTMLButtonElement
    expect(button).toHaveAttribute("data-disabled")
    expect(button).toHaveAttribute("data-value", "from")

    button.dispatchEvent(new MouseEvent("click", { bubbles: true }))

    expect(button).toHaveAttribute("data-value", "from")
  })

  test("should be render Flip with orientation", async () => {
    await render(
      <Flip
        disabled
        from={<BoxIcon />}
        orientation="vertical"
        to={<BoxIcon />}
      />,
    )

    const button = page.getByRole("button").element() as HTMLButtonElement
    expect(button).toHaveAttribute("data-orientation", "vertical")
  })

  test("should warn when dimensions of from element and to element don't match", async () => {
    const mockElementDimensions = (
      height: { from: number; to: number },
      width: { from: number; to: number },
    ) => {
      Object.defineProperty(HTMLElement.prototype, "offsetHeight", {
        configurable: true,
        get() {
          return this.className.includes("ui-flip__item--from")
            ? height.from
            : height.to
        },
      })

      Object.defineProperty(HTMLElement.prototype, "offsetWidth", {
        configurable: true,
        get() {
          return this.className.includes("ui-flip__item--from")
            ? width.from
            : width.to
        },
      })
    }

    const consoleWarnSpy = vi.spyOn(console, "warn").mockImplementation(noop)

    mockElementDimensions({ from: 16, to: 32 }, { from: 16, to: 32 })

    await render(
      <Flip
        from={<BoxIcon data-testid="test-icon" />}
        to={<BoxIcon data-testid="test-icon" />}
      />,
    )

    expect(consoleWarnSpy).toHaveBeenCalledExactlyOnceWith(
      'Flip: "from" element (width: 16px, height: 16px) does not match "to" element (width: 32px, height: 32px). Please ensure both elements have the same dimensions.',
    )

    consoleWarnSpy.mockRestore()
  })
})

"use client"

import type { Variants } from "motion/react"
import type { ReactNode } from "react"
import type { KeyframeIdent, Orientation, ThemeProps } from "@yamada-ui/react"
import type { HTMLMotionProps } from "../motion"
import type { FlipStyle } from "./flip.style"
import { useMemo, useRef, useState } from "react"
import { createSlotComponent, dataAttr, handlerAll, useSafeLayoutEffect } from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { motion } from "../motion"
import { flipStyle } from "./flip.style"

const flipVariants: Variants = {
  enter: ({ ident, orientation, visible }) => ({
    [orientation === "horizontal" ? "rotateY" : "rotateX"]:
      ident === "from" ? (visible ? 180 : 0) : visible ? 0 : 180,
  }),
  exit: ({ ident, orientation }) => ({
    [orientation === "horizontal" ? "rotateY" : "rotateX"]:
      ident === "from" ? 0 : 180,
  }),
}

interface Rect {
  height?: number
  width?: number
}

export interface FlipProps
  extends Omit<HTMLMotionProps<"button">, "onChange">, ThemeProps<FlipStyle> {
  /**
   * Passing React elements to "from" is required.
   */
  from: ReactNode
  /**
   * Passing React elements to "to" is required.
   */
  to: ReactNode
  /**
   * You can set the initial state.
   *
   * @default 'from'
   */
  defaultValue?: KeyframeIdent
  /**
   * The animation delay.
   *
   * @default 0
   */
  delay?: number
  /**
   * If `true`, the component is disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The animation duration.
   *
   * @default 0.4
   */
  duration?: number
  /**
   * The orientation of the flip effect. Determines whether the flip occurs horizontally or vertically.
   *
   * @default 'horizontal'
   */
  orientation?: Orientation
  /**
   * If `true`, the component is readonly.
   *
   * @default false
   */
  readOnly?: boolean
  /**
   * Use this when you want to control the animation from outside the component.
   */
  value?: KeyframeIdent
  /**
   * This is a callback function that is called when the animation state changes.
   */
  onChange?: (value: KeyframeIdent) => void
}

const {
  PropsContext: FlipPropsContext,
  usePropsContext: useFlipPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<FlipProps, FlipStyle>("flip", flipStyle)

export { FlipPropsContext, useFlipPropsContext }

/**
 * `Flip` is an animation component that alternates between flipping two elements.
 *
 * @see https://yamada-ui.com/docs/components/flip
 */
export const Flip = withProvider(
  ({
    defaultValue = "from",
    delay = 0,
    disabled,
    duration = 0.4,
    from,
    orientation = "horizontal",
    readOnly,
    to,
    transition = {},
    value: valueProp,
    onChange,
    onClick: onClickProp,
    ...rest
  }) => {
    const [{ height, width }, setRect] = useState<Rect>({})
    const fromRef = useRef<HTMLDivElement | null>(null)
    const toRef = useRef<HTMLDivElement | null>(null)
    const [value, setValue] = useControllableState({
      defaultValue,
      value: valueProp,
      onChange,
    })
    const visible = value === "to"

    const style = useMemo(
      () => ({
        height: height ? `${height}px` : "auto",
        width: width ? `${width}px` : "auto",
      }),
      [width, height],
    )

    const onClick = () => {
      if (readOnly) return

      setValue((prev) => (prev === "from" ? "to" : "from"))
    }

    useSafeLayoutEffect(() => {
      const from = fromRef.current
      const to = toRef.current

      if (!from || !to) return

      if (
        from.offsetWidth !== to.offsetWidth ||
        from.offsetHeight !== to.offsetHeight
      ) {
        console.warn(
          `Flip: "from" element (width: ${from.offsetWidth}px, height: ${from.offsetHeight}px) does not match "to" element (width: ${to.offsetWidth}px, height: ${to.offsetHeight}px). Please ensure both elements have the same dimensions.`,
        )
      }

      setRect({ height: from.offsetHeight, width: from.offsetWidth })
    }, [fromRef, toRef])

    return (
      <motion.button
        type="button"
        style={style}
        data-disabled={dataAttr(disabled)}
        data-orientation={orientation}
        data-readonly={dataAttr(readOnly)}
        data-value={value}
        disabled={disabled}
        onClick={handlerAll(onClickProp, onClick)}
        {...rest}
      >
        <FlipFrom
          ref={fromRef}
          custom={{ orientation, visible }}
          transition={{ delay, duration, ...transition }}
        >
          {from}
        </FlipFrom>

        <FlipTo
          ref={toRef}
          custom={{ orientation, visible }}
          transition={{ delay, duration, ...transition }}
        >
          {to}
        </FlipTo>
      </motion.button>
    )
  },
  "root",
)()

interface FlipFromProps extends HTMLMotionProps<"span"> {}

const FlipFrom = withContext<"span", FlipFromProps>(
  ({ custom, ...rest }) => {
    return (
      <motion.span
        animate="enter"
        custom={{ ident: "from", ...custom }}
        initial="exit"
        variants={flipVariants}
        {...rest}
      />
    )
  },
  ["item", "from"],
)()

interface FlipToProps extends HTMLMotionProps<"span"> {}

const FlipTo = withContext<"span", FlipToProps>(
  ({ custom, ...rest }) => {
    return (
      <motion.span
        animate="enter"
        custom={{ ident: "to", ...custom }}
        initial="exit"
        variants={flipVariants}
        {...rest}
      />
    )
  },
  ["item", "to"],
)()
